UPDATE words SET example_sentence = 'Repeated practice and review will reinforce the vocabulary knowledge that students have acquired throughout the semester.' WHERE word = 'reinforce' AND level = 'high_2';
UPDATE words SET example_sentence = 'Journalists have a responsibility to scrutinize government policies and hold public officials accountable for their decisions.' WHERE word = 'scrutinize' AND level = 'high_2';
